  "Zabudowa systemów BESS w bezpiecznej, wentylowanej obudowie.": { uk: "Інтеграція систем BESS у безпечному вентильованому корпусі.", hy: "BESS համակարգերի հավաքում անվտանգ, օդափոխվող պատյանում։" },
  "Zabudowa techniczna w formule kontenerowej": { uk: "Технічна інтеграція у контейнерному форматі", hy: "Տեխնիկական հավաքում կոնտեյներային ձևաչափով" },
  "Zabudowa z wyciszeniem akustycznym i układem spalin.": { uk: "Виконання зі звукоізоляцією та системою відведення вихлопів.", hy: "Կատարում՝ ակուստիկ մեկուսացմամբ և արտանետումների համակարգով։" },
  "Zabudowa<br>kontenerowa dla<br>energetyki<span class=\"dot\">.</span>": { uk: "Контейнерне<br>виконання для<br>енергетики<span class=\"dot\">.</span>", hy: "Կոնտեյներային<br>կատարում<br>էներգետիկայի համար<span class=\"dot\">.</span>" },
  "Zabudowa<br>kontenerowa<br><strong>szyta na miarę</strong><span class='dot'>.</span>": { uk: "Контейнерне<br>виконання<br><strong>під ваші потреби</strong><span class='dot'>.</span>", hy: "Կոնտեյներային<br>կատարում<br><strong>ձեր չափով</strong><span class='dot'>.</span>" },
  "Zabudowujemy urządzenia naszych klientów w kontenerach — pod ich marką, bez inwestycji we własną halę produkcyjną.": { uk: "Інтегруємо обладнання наших клієнтів у контейнери — під їхнім брендом, без інвестицій у власний виробничий цех.", hy: "Հաճախորդների սարքավորումները հավաքում ենք կոնտեյներներում՝ նրանց ապրանքանիշով, առանց սեփական արտադրամասում ներդրման։" },
  "Zakres INVERSIS": { uk: "Обсяг робіт INVERSIS", hy: "INVERSIS-ի ծավալը" },
  "Zakłady z niestabilnym zasilaniem": { uk: "Підприємства з нестабільним живленням", hy: "Անկայուն սնուցմամբ ձեռնարկություններ" },
  "Zapewniamy uruchomienie, serwis i wsparcie techniczne w całym cyklu życia.": { uk: "Забезпечуємо пусконалагодження, сервіс і технічну підтримку протягом усього життєвого циклу.", hy: "Ապահովում ենք գործարկում, սպասարկում և տեխնիկական աջակցություն ողջ կյանքի ցիկլի ընթացքում։" },
  "Zaplecze paliwowe budów i inwestycji": { uk: "Паливне забезпечення будівництв та інвестицій", hy: "Շինարարությունների և ներդրումների վառելիքային ապահովում" },
  "Zapraszamy na spotkanie połączone z wizją lokalną w hali produkcyjnej — to najlepszy sposób, by ocenić nasze możliwości i omówić model współpracy.": { uk: "Запрошуємо на зустріч із візитом до виробничого цеху — це найкращий спосіб оцінити наші можливості й обговорити модель співпраці.", hy: "Հրավիրում ենք հանդիպման՝ արտադրամասի այցելությամբ․ սա լավագույն ձևն է գնահատելու մեր հնարավորությունները և քննարկելու համագործակցության մոդելը։" },
  "Zaprojektujemy autonomiczny moduł zasilania z magazynem energii, PV i agregatem.": { uk: "Спроєктуємо автономний модуль живлення з накопичувачем енергії, PV та генератором.", hy: "Կնախագծենք ինքնավար սնուցման մոդուլ՝ էներգիայի պահեստով, PV-ով և գեներատորով։" },
  "Zaprojektujemy autonomiczny moduł zasilania.": { uk: "Спроєктуємо автономний модуль живлення.", hy: "Կնախագծենք ինքնավար սնուցման մոդուլ։" },
